	@Test
	void batchesRightEvaluationAndPreservesUnmatchedRowsAsMultiset() {
		String previousBatchSize = System.getProperty(LmdbIdBatchJoinIterator.BATCH_SIZE_PROPERTY);
		System.setProperty(LmdbIdBatchJoinIterator.BATCH_SIZE_PROPERTY, "16");
		BatchCapableRightStep right = new BatchCapableRightStep();
		try (CloseableIteration<BindingSet> iter = LmdbIdLeftJoinIterator.getInstance(new LeftStep(35),
				EmptyBindingSet.getInstance(), right)) {
			List<BindingSet> rows = Iterations.asList(iter);

			assertThat(rows).hasSize(35);
			assertThat(right.batchCalls).isEqualTo(3);
			assertThat(right.scalarCalls).isZero();
			assertThat(rows.stream().filter(row -> row.hasBinding("right"))).hasSize(18);
			assertThat(rows.stream().filter(row -> !row.hasBinding("right"))).hasSize(17);
			assertThat(rows)
					.extracting(row -> row.getValue("left").stringValue())
					.containsExactlyInAnyOrderElementsOf(leftValues(35));
		} finally {
			if (previousBatchSize == null) {
				System.clearProperty(LmdbIdBatchJoinIterator.BATCH_SIZE_PROPERTY);
			} else {
				System.setProperty(LmdbIdBatchJoinIterator.BATCH_SIZE_PROPERTY, previousBatchSize);
			}
		}
	}

